    authHeader,
    body: { q: query },
    skip: false,
    billIds
  }
};

// ============================================================
// STEP 3: Query payment links for each bill
// ============================================================

const ACCOUNT_ID = '9231063';
const CONSUMER_KEY = '9129dd37d3564cc47cf6faf331d0cbc84266b0bab347c2e94fb428b7cb9b3a0a';
const CONSUMER_SECRET = '157e69200b8504dc6133f28b81025a96755a2b81f4acde7d66538f561687ffc6';
const TOKEN_ID = 'bb9ee805f466c066d3a0b3027d70fee9f9a6219c7e635d25095ec0f38ecd568a';
const TOKEN_SECRET = 'd27eabcb80decf6fd5b8a5c4914617972157875458eb15dbfa9fbb32db8af5ca';

// Store bill data for later merge
const rawData = $input.item.json;
const parsed = JSON.parse(rawData.data);
const billItems = parsed?.items || [];

const billIds = billItems.map(b => b.bill_id).filter(Boolean);

if (billIds.length === 0) {
  return {
    json: {
      billItems,
      paymentItems: [],
      skipPayments: true
    }
  };
}

const baseUrl = `https://${ACCOUNT_ID}.suitetalk.api.netsuite.com/services/rest/query/v1/suiteql`;
const limit = 1000;
const offset = 0;
const fullUrl = `${baseUrl}?limit=${limit}&offset=${offset}`;

const crypto = require('crypto');
const oauth_nonce = crypto.randomBytes(16).toString('hex');
const oauth_timestamp = Math.floor(Date.now() / 1000).toString();

const queryParams = { limit: limit.toString(), offset: offset.toString() };
const oauthParams = {
  oauth_consumer_key: CONSUMER_KEY,
  oauth_nonce,
  oauth_signature_method: 'HMAC-SHA256',
  oauth_timestamp,
  oauth_token: TOKEN_ID,
  oauth_version: '1.0'
};

const allParams = { ...queryParams, ...oauthParams };
const paramString = Object.keys(allParams)
  .sort()
  .map(key => `${encodeURIComponent(key)}=${encodeURIComponent(allParams[key])}`)
  .join('&');

const signatureBaseString = ['POST', encodeURIComponent(baseUrl), encodeURIComponent(paramString)].join('&');
const signingKey = `${encodeURIComponent(CONSUMER_SECRET)}&${encodeURIComponent(TOKEN_SECRET)}`;
const oauth_signature = crypto.createHmac('sha256', signingKey).update(signatureBaseString).digest('base64');

const authHeader =
  `OAuth realm="${ACCOUNT_ID}", ` +
  `oauth_consumer_key="${CONSUMER_KEY}", ` +
  `oauth_token="${TOKEN_ID}", ` +
  `oauth_signature_method="HMAC-SHA256", ` +
  `oauth_timestamp="${oauth_timestamp}", ` +
  `oauth_nonce="${oauth_nonce}", ` +
  `oauth_version="1.0", ` +
  `oauth_signature="${encodeURIComponent(oauth_signature)}"`;

const idList = billIds.join(', ');
const query = `SELECT ntll.previousdoc AS bill_id, ntll.nextdoc AS payment_id, ntll.nextdate AS payment_date, ntll.foreignamount AS payment_amount, BUILTIN.DF(tal.account) AS bank_account FROM nexttransactionlinelink ntll LEFT JOIN transactionaccountingline tal ON tal.transaction = ntll.nextdoc AND tal.credit > 0 WHERE ntll.previousdoc IN (${idList}) AND ntll.previoustype = 'VendBill' AND ntll.nexttype = 'VendPymt'`;

return {
  json: {
    url: fullUrl,
    authHeader,
    body: { q: query },
    billItems,
    skipPayments: false
  }
};

// ============================================================
// FINAL: Merge bills + payments into clean response
// ============================================================

const rawData = $input.item.json;
const poInternalId = $('Code: Step 1 - Find Bill Links').item.json.poInternalId;


// Payment data comes from HTTP response
let paymentItems = [];
try {
  const paymentParsed = JSON.parse(rawData.data);
  paymentItems = paymentParsed?.items || [];
} catch (e) {
  paymentItems = [];
}

// Bill data was passed through from Step 3 Code node
// We need to get it from the execution context
// Since HTTP node overwrites json, we get billItems from the Code node before HTTP
const step3Node = $('Code: Step 3 - Build Payment Query');
const billItems = step3Node.item.json.billItems || [];

// Build payment lookup: bill_id -> payment data
const paymentMap = {};
for (const p of paymentItems) {
  const billId = p.bill_id;
  if (!paymentMap[billId]) {
    paymentMap[billId] = [];
  }
  paymentMap[billId].push({
    payment_id: p.payment_id,
    payment_date: p.payment_date,
    payment_amount: parseFloat(p.payment_amount) || 0,
    bank_account: p.bank_account || null
  });
}

// Merge bills with payment data
const bills = billItems.map(bill => {
  const billId = bill.bill_id;
  const payments = paymentMap[billId] || [];
  const totalPaid = payments.reduce((sum, p) => sum + Math.abs(p.payment_amount), 0);
  const latestPayment = payments.length > 0
    ? payments.sort((a, b) => {
        // Sort by date descending (DD/MM/YYYY format)
        const [da, ma, ya] = (a.payment_date || '').split('/');
        const [db, mb, yb] = (b.payment_date || '').split('/');
        return new Date(yb, mb - 1, db) - new Date(ya, ma - 1, da);
      })[0]
    : null;

  return {
    bill_id: billId,
    bill_number: bill.bill_number || bill.tranid,
    bill_date: bill.bill_date || bill.trandate,
    bill_total: Math.abs(parseFloat(bill.bill_total || bill.total) || 0),
    bill_status: bill.bill_status || bill.estatus,
    currency: bill.moneda,
    exchange_rate: parseFloat(bill.tipo_cambio || bill.exchangerate) || null,
    account: bill.cuenta || null,
    subsidiary: bill.subsidiaria || null,
    memo: bill.memo || null,
    // Payment data
    is_paid: (bill.bill_status || bill.estatus || '').includes('Pagado'),
    payment_date: latestPayment?.payment_date || null,
    payment_amount: totalPaid > 0 ? Math.round(totalPaid * 100) / 100 : null,
    payment_count: payments.length,
    bank_account: latestPayment?.bank_account || null

  };
});

// Summary
const paidBills = bills.filter(b => b.is_paid);
const openBills = bills.filter(b => !b.is_paid);

return {
  json: {
    bills,
    poInternalId,
    summary: {
      total_bills: bills.length,
      total_billed: Math.round(bills.reduce((s, b) => s + b.bill_total, 0) * 100) / 100,
      paid_count: paidBills.length,
      paid_total: Math.round(paidBills.reduce((s, b) => s + b.bill_total, 0) * 100) / 100,
      open_count: openBills.length,
      open_total: Math.round(openBills.reduce((s, b) => s + b.bill_total, 0) * 100) / 100
    }
  }
};

